import{_ as e,o as n,c as s,ae as t}from"./chunks/framework.D0EcU_Ug.js";const h=JSON.parse('{"title":"Linux 生存手册","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux-survival-guide.md","filePath":"notes/linux-survival-guide.md"}'),i={name:"notes/linux-survival-guide.md"};function o(r,a,l,d,c,u){return n(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="linux-生存手册" tabindex="-1">Linux 生存手册 <a class="header-anchor" href="#linux-生存手册" aria-label="Permalink to &quot;Linux 生存手册&quot;">​</a></h1><p>这页不再堆具体问题，改成总览。</p><p>以前我喜欢把所有零碎经验塞进一篇长文，写的时候挺爽，等真要找东西时就开始痛苦。现在这篇只负责带路，具体问题都拆成单独文章。</p><div class="note-grid"><a class="note-card" href="/linux-docs/notes/network/"><h3>网络与连接</h3><p>校园网和代理，先把网打通。</p></a><a class="note-card" href="/linux-docs/notes/graphics/"><h3>显卡与图形</h3><p>Nvidia、Wayland、EGL，这一栏负责所有“像玄学”的显示问题。</p></a><a class="note-card" href="/linux-docs/notes/desktop/"><h3>桌面与交互</h3><p>Keyring、登录器、Alt+Tab、鼠标指针，这些每天都要碰。</p></a><a class="note-card" href="/linux-docs/notes/system/"><h3>系统、磁盘与引导</h3><p>Btrfs、systemd-boot、UKI，属于不出事就不碰，一出事就要命。</p></a><a class="note-card" href="/linux-docs/notes/interop/"><h3>跨系统协作</h3><p>Windows 和 Linux 混着用时的一些具体问题。</p></a><a class="note-card" href="/linux-docs/notes/nix/"><h3>NixOS / Nix</h3><p>最近的主线。命令和工作流都往这边收。</p></a></div><h2 id="还保留这页的原因" tabindex="-1">还保留这页的原因 <a class="header-anchor" href="#还保留这页的原因" aria-label="Permalink to &quot;还保留这页的原因&quot;">​</a></h2><p>因为“Linux 生存手册”这个名字还挺像这个站现在的样子。只不过正文已经被拆出来了，这页以后更像封面，而不是仓库。</p>',6)])])}const x=e(i,[["render",o]]);export{h as __pageData,x as default};
